"use client";

import { useState, useMemo, useCallback, useId } from "react";
import { validateCPF, formatCPF } from "@/lib/utils";

interface BookingClientProps {
  therapistId: string;
  therapistName: string;
  sessionPrice: number;
  sessionDuration: number;
  availabilitySlots: Array<{
    day_of_week: number;
    start_time: string;
    end_time: string;
  }>;
  bookedTimes: string[];
  slug: string;
}

interface BookingForm {
  name: string;
  email: string;
  phone: string;
  cpf: string;
}

const DAYS = ["Dom", "Seg", "Ter", "Qua", "Qui", "Sex", "Sáb"];

export default function BookingClient({
  therapistId,
  therapistName,
  sessionPrice,
  sessionDuration,
  availabilitySlots,
  bookedTimes,
  slug,
}: BookingClientProps) {
  const [selectedSlot, setSelectedSlot] = useState<string | null>(null);
  const [step, setStep] = useState<"select" | "form" | "processing">("select");
  const [form, setForm] = useState<BookingForm>({
    name: "",
    email: "",
    phone: "",
    cpf: "",
  });
  const [error, setError] = useState<string | null>(null);
  const formId = useId();

  // Generate next 21 days with available slots
  const daysWithSlots = useMemo(() => {
    const slotsByDay: Record<number, typeof availabilitySlots> = {};
    for (const slot of availabilitySlots) {
      if (!slotsByDay[slot.day_of_week]) slotsByDay[slot.day_of_week] = [];
      slotsByDay[slot.day_of_week].push(slot);
    }

    const result: Array<{
      date: Date;
      dayOfWeek: number;
      label: string;
      times: Array<{ time: string; iso: string; booked: boolean }>;
    }> = [];

    for (let i = 1; i <= 21; i++) {
      const d = new Date();
      d.setDate(d.getDate() + i);
      d.setHours(0, 0, 0, 0);
      const dow = d.getDay();

      if (!slotsByDay[dow]) continue;

      const times: Array<{ time: string; iso: string; booked: boolean }> = [];
      for (const slot of slotsByDay[dow]) {
        const generated = generateTimeSlots(
          slot.start_time,
          slot.end_time,
          sessionDuration
        );
        for (const t of generated) {
          const [h, m] = t.split(":").map(Number);
          const slotDate = new Date(d);
          slotDate.setHours(h, m, 0, 0);
          const iso = slotDate.toISOString();

          const isBooked = bookedTimes.some(
            (b) => Math.abs(new Date(b).getTime() - slotDate.getTime()) < 3600000
          );

          times.push({ time: t, iso, booked: isBooked });
        }
      }

      if (times.length > 0) {
        result.push({
          date: d,
          dayOfWeek: dow,
          label: d.toLocaleDateString("pt-BR", {
            weekday: "short",
            day: "2-digit",
            month: "2-digit",
          }),
          times,
        });
      }
    }

    return result;
  }, [availabilitySlots, bookedTimes, sessionDuration]);

  const handleSlotClick = useCallback(
    (iso: string, booked: boolean) => {
      if (booked) return;
      setSelectedSlot(iso);
      setStep("form");
      setError(null);
    },
    []
  );

  const handleSubmit = useCallback(async () => {
    if (!selectedSlot || !form.name.trim() || !form.email.includes("@")) {
      setError("Preencha todos os campos corretamente.");
      return;
    }

    if (form.cpf && !validateCPF(form.cpf)) {
      setError("CPF inválido. Verifique e tente novamente.");
      return;
    }

    setStep("processing");
    setError(null);

    try {
      const res = await fetch("/api/booking/checkout", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          therapistId,
          scheduledAt: selectedSlot,
          patientName: form.name,
          patientEmail: form.email,
          patientPhone: form.phone,
          patientCpf: form.cpf || undefined,
          slug,
        }),
      });

      if (!res.ok) {
        const err = await res.json().catch(() => ({}));
        throw new Error(
          (err as { error?: string }).error ?? `Erro ${res.status}`
        );
      }

      const json = (await res.json()) as { data: { checkoutUrl: string } };

      // Redirect to Stripe checkout
      window.location.href = json.data.checkoutUrl;
    } catch (e) {
      setError(e instanceof Error ? e.message : "Erro ao processar agendamento");
      setStep("form");
    }
  }, [selectedSlot, form, therapistId, slug]);

  const selectedDate = selectedSlot
    ? new Date(selectedSlot).toLocaleDateString("pt-BR", {
        weekday: "long",
        day: "2-digit",
        month: "long",
      })
    : "";
  const selectedTime = selectedSlot
    ? new Date(selectedSlot).toLocaleTimeString("pt-BR", {
        hour: "2-digit",
        minute: "2-digit",
      })
    : "";

  const inputStyle: React.CSSProperties = {
    width: "100%",
    padding: "12px 16px",
    borderRadius: 12,
    background: "var(--color-surface)",
    border: "1px solid var(--color-border-subtle)",
    color: "var(--color-text-primary)",
    fontFamily: "var(--font-sans)",
    fontSize: 14,
    outline: "none",
  };

  return (
    <div>
      {/* Step indicator */}
      <div className="flex gap-2 mb-6 items-center">
        {[
          { n: 1, label: "Horário" },
          { n: 2, label: "Dados" },
          { n: 3, label: "Pagamento" },
        ].map((s, i, arr) => {
          const isActive =
            (s.n === 1 && step === "select") ||
            (s.n === 2 && step === "form") ||
            (s.n === 3 && step === "processing");
          return (
            <div key={s.n} className="flex items-center gap-2">
              <div
                className={`w-7 h-7 rounded-full flex items-center justify-center text-[12px] font-semibold border ${
                  isActive
                    ? "bg-[var(--color-brand)] text-black border-[var(--color-brand)]"
                    : "bg-[var(--color-surface)] text-[var(--color-text-muted)] border-[var(--color-border-subtle)]"
                } transition-colors duration-300`}
              >
                {s.n}
              </div>
              <span
                className={`text-[13px] ${
                  isActive ? "text-[var(--color-text-primary)] font-medium" : "text-[var(--color-text-muted)]"
                }`}
              >
                {s.label}
              </span>
              {i < arr.length - 1 && (
                <div className="w-8 h-[1px] bg-[var(--color-border-subtle)]" />
              )}
            </div>
          );
        })}
      </div>

      {/* Error */}
      {error && (
        <div className="px-4 py-3 bg-red-500/10 border border-red-500/30 rounded-xl text-red-500 text-[13px] mb-4 flex items-center gap-2">
          <span>❌</span> {error}
        </div>
      )}

      {/* Step 1: Select slot */}
      {(step === "select" || step === "form") && (
        <div className="bg-[var(--color-surface)]/40 border border-[var(--color-border-subtle)] rounded-2xl p-7 mb-5 backdrop-blur-md">
          <h2 className="font-[family-name:var(--font-display)] text-[24px] font-light text-[var(--color-text-primary)] mb-5">
            Escolha o horário
          </h2>

          {daysWithSlots.length === 0 ? (
            <div className="text-center py-8 text-[var(--color-text-muted)]">
              Não há horários disponíveis no momento.
            </div>
          ) : (
            <div
              className={`flex flex-col gap-5 ${
                step === "form" ? "max-h-[320px] overflow-y-auto pr-2 custom-scrollbar" : ""
              }`}
            >
              {daysWithSlots.map((day) => (
                <div key={day.label}>
                  <div className="text-[13px] text-[var(--color-text-secondary)] font-medium mb-2.5">
                    {DAYS[day.dayOfWeek]} ·{" "}
                    {day.date.toLocaleDateString("pt-BR", {
                      day: "2-digit",
                      month: "2-digit",
                    })}
                  </div>
                  <div className="flex flex-wrap gap-2.5">
                    {day.times.map((t) => {
                      const isSelected = selectedSlot === t.iso;
                      return (
                        <button
                          key={t.iso}
                          type="button"
                          disabled={t.booked}
                          onClick={() => handleSlotClick(t.iso, t.booked)}
                          className={`px-4 py-2.5 rounded-xl text-[14px] font-medium transition-all duration-200 ${
                            isSelected
                              ? "bg-[var(--color-brand)] text-black border-2 border-[var(--color-brand)] shadow-[0_0_15px_rgba(var(--color-brand-rgb),0.3)]"
                              : t.booked
                              ? "bg-[var(--color-surface)] text-[var(--color-text-muted)] border border-[var(--color-border-subtle)] cursor-not-allowed opacity-40 line-through"
                              : "bg-[var(--color-brand)]/5 text-[var(--color-brand)] border border-[var(--color-brand)]/30 hover:bg-[var(--color-brand)]/10 hover:border-[var(--color-brand)]/50 cursor-pointer"
                          }`}
                        >
                          {t.time}
                        </button>
                      );
                    })}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* Step 2: Form */}
      {step === "form" && selectedSlot && (
        <div className="bg-[var(--color-surface)]/50 border border-[var(--color-border-subtle)] rounded-2xl p-7 animate-[fadeUp_.25s_ease-out_both] backdrop-blur-md">
          <h2 className="font-[family-name:var(--font-display)] text-[24px] font-light text-[var(--color-text-primary)] mb-1.5">
            Seus dados
          </h2>
          <p className="text-[13px] text-[var(--color-text-muted)] mb-5">
            Sessão com{" "}
            <span className="text-[#3b82f6]">{therapistName}</span> em{" "}
            <span className="text-[#fbbf24]">
              {selectedDate} às {selectedTime}
            </span>
          </p>

          <div className="flex flex-col gap-3">
            <div>
              <label
                htmlFor={`${formId}-name`}
                className="text-[11px] text-[var(--color-text-muted)] uppercase tracking-[0.08em] block mb-1.5"
              >
                Nome completo *
              </label>
              <input
                id={`${formId}-name`}
                style={inputStyle}
                className="focus:border-[var(--color-brand)] focus:ring-1 focus:ring-[var(--color-brand)] bg-[var(--color-background)]"
                placeholder="Seu nome"
                value={form.name}
                onChange={(e) =>
                  setForm((f) => ({ ...f, name: e.target.value }))
                }
                aria-label="Nome completo"
              />
            </div>

            <div>
              <label
                htmlFor={`${formId}-email`}
                className="text-[11px] text-[var(--color-text-muted)] uppercase tracking-[0.08em] block mb-1.5"
              >
                Email *
              </label>
              <input
                id={`${formId}-email`}
                style={inputStyle}
                className="focus:border-[var(--color-brand)] focus:ring-1 focus:ring-[var(--color-brand)] bg-[var(--color-background)]"
                placeholder="seu@email.com"
                type="email"
                value={form.email}
                onChange={(e) =>
                  setForm((f) => ({ ...f, email: e.target.value }))
                }
                aria-label="Email"
              />
            </div>

            <div>
              <label
                htmlFor={`${formId}-phone`}
                className="text-[11px] text-[var(--color-text-muted)] uppercase tracking-[0.08em] block mb-1.5"
              >
                Telefone (opcional)
              </label>
              <input
                id={`${formId}-phone`}
                style={inputStyle}
                className="focus:border-[var(--color-brand)] focus:ring-1 focus:ring-[var(--color-brand)] bg-[var(--color-background)]"
                placeholder="(11) 99999-0000"
                value={form.phone}
                onChange={(e) =>
                  setForm((f) => ({ ...f, phone: e.target.value }))
                }
                aria-label="Telefone"
              />
            </div>

            <div>
              <label
                htmlFor={`${formId}-cpf`}
                className="text-[11px] text-[var(--color-text-muted)] uppercase tracking-[0.08em] block mb-1.5"
              >
                CPF (opcional)
              </label>
              <input
                id={`${formId}-cpf`}
                style={inputStyle}
                className="focus:border-[var(--color-brand)] focus:ring-1 focus:ring-[var(--color-brand)] bg-[var(--color-background)]"
                placeholder="000.000.000-00"
                value={form.cpf ? formatCPF(form.cpf) : ""}
                onChange={(e) => {
                  const raw = e.target.value.replace(/\D/g, "").slice(0, 11);
                  setForm((f) => ({ ...f, cpf: raw }));
                }}
                inputMode="numeric"
                aria-label="CPF"
              />
            </div>
          </div>

          {/* Summary & submit */}
          <div className="mt-5 p-4 bg-[var(--color-surface-hover)]/30 rounded-xl border border-[var(--color-border-subtle)] flex flex-col sm:flex-row justify-between items-center sm:items-start gap-4">
            <div className="text-center sm:text-left">
              <div className="text-[11px] text-[var(--color-text-muted)] mb-1">
                Valor da sessão
              </div>
              <div className="font-[family-name:var(--font-display)] text-[28px] font-light text-[#fbbf24]">
                R$ {sessionPrice.toFixed(2)}
              </div>
            </div>
            <button
              type="button"
              onClick={handleSubmit}
              className="w-full sm:w-auto px-8 py-3.5 bg-[var(--color-brand)] text-black rounded-xl border-none text-[15px] font-semibold cursor-pointer shadow-[0_4px_24px_rgba(var(--color-brand-rgb),0.25)] hover:shadow-[0_4px_32px_rgba(var(--color-brand-rgb),0.4)] hover:scale-[1.02] transition-all duration-300"
            >
              Ir para Pagamento →
            </button>
          </div>

          <div className="mt-3 text-[11px] text-[var(--color-text-muted)] text-center tracking-wide font-light">
            🔒 Pagamento seguro via Stripe · Dados protegidos por LGPD
          </div>
        </div>
      )}

      {/* Step 3: Processing */}
      {step === "processing" && (
        <div className="bg-[var(--color-surface)]/50 border border-[var(--color-border-subtle)] rounded-2xl p-[60px_28px] text-center backdrop-blur-md">
          <div className="w-12 h-12 border-4 border-[var(--color-border-subtle)] border-t-[var(--color-brand)] rounded-full mx-auto mb-5 animate-spin" />
          <div className="font-[family-name:var(--font-display)] text-[22px] font-light text-[var(--color-text-primary)] mb-2">
            Redirecionando para pagamento...
          </div>
          <div className="text-[13px] text-[var(--color-text-muted)]">
            Você será redirecionado ao Stripe em instantes.
          </div>
        </div>
      )}
    </div>
  );
}

function generateTimeSlots(
  start: string,
  end: string,
  durationMin: number
): string[] {
  const slots: string[] = [];
  const [sh, sm] = start.split(":").map(Number);
  const [eh, em] = end.split(":").map(Number);
  let current = sh * 60 + sm;
  const endMin = eh * 60 + em;

  while (current + durationMin <= endMin) {
    const h = Math.floor(current / 60);
    const m = current % 60;
    slots.push(`${String(h).padStart(2, "0")}:${String(m).padStart(2, "0")}`);
    current += durationMin;
  }

  return slots;
}
